command.text:

declare @invoke nvarchar(4000)
select @invoke = ''
&ListDeleted;
&PostDeleted;
select @invoke as invoke

        /* <flatten type="Javascript"> */
var f = this, field = f.getItem('rkey').field;
var imgname = getFileName($get('imageupload').value), allowExt = 'gif,png,jpg,jpeg';
var err = (f._language == 'v' ? 'Định dạng tệp ảnh không đúng.' : 'Invalid file type.');

if (imgname != '') {
  var ext = imgname.split('.').pop();
  if (allowExt.indexOf(ext.toLowerCase()) < 0) {
    f._checked = false;
    $message.show(err);
  }
  else {
    var k = getRandomKey(12), h = f.getItemValue('ticket');
    var form = $get('uploadForm');
    f.setItemValue('rkey', k);
    form.action = '../AppHandler/Image.ashx?t=upload&k=' + k + '&h=' + h;
    form.submit();
  }
  field.FilterSource = '';
}
else {
  f.setItemValue('rkey', '');
  field.FilterSource = 'Ignore';
}
/* </flatten> */
        &CheckValidEmailCommandChecking;
        &ListChecking;
        &PostChecking;

script.text:

function active$hrRMApplicantProfileInputForm(f) {
  $get('empImage').parentNode.style.maxHeight = 'none';
  f.add_onResponseComplete(on$hrRMApplicantProfileInputForm$ResponseComplete);
  f.add_commandEvent(on$hrRMApplicantProfileInputForm$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$hrRMApplicantProfileInputForm$Tab);
  f._tabContainer._loaded = true;
  $addHandler($get('imageupload'), 'change', onFileSelected);
  init$hrRMApplicantProfileInputForm(f);

      &ListCreate;
      &PostCreate;
}
function scatter$hrRMApplicantProfileInputForm(f) {
  loadApplicantImage(f);
  init$hrRMApplicantProfileInputForm(f);

      &ListScattering;
      &PostScattering;
}
function close$hrRMApplicantProfileInputForm(f) {
  try {$removeHandler($get('imageupload'), 'change', onFileSelected);} catch (ex) {}
  try {f.remove_commandEvent(on$hrRMApplicantProfileInputForm$ExecuteCommand);} catch (ex) {}
  try {f.remove_onResponseComplete(on$hrRMApplicantProfileInputForm$ResponseComplete)} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$hrRMApplicantProfileInputForm$Tab);} catch (ex) {}

      &ListDispose;
      &PostDispose;
}
function onChange$hrRMApplicantProfileInputForm$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ma_vtr', 'cmnd_so', 'ngay_kham', 'cap_dt', 'dqtlv', 'ma_nn', 'dcc'&ListTabChange;&PostTabChange;]);&PostTabFocus;}
function on$hrRMApplicantProfileInputForm$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_hs');
      break;
    case 'DefautFormValue':
      f.setItemValue('ticket', result[0].Value);
      break;
    &ListResponseTicket;
    default:
      break;
  }
}
function on$hrRMApplicantProfileInputForm$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('dqtlv')._controlBehavior, u = f.getItem('dcc')._controlBehavior;
  switch (action) {
    case 'Shown':
      $get('imageupload').disabled = (f._action == 'View');
      &ListShown;
      &PostShown;
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      u.setSequenceNumber('line_nbr');
      u.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function init$hrRMApplicantProfileInputForm(f) {
  var g = f.grid, l = $get('imageupload');
  l.value = ''; l.disabled = (f._action == 'View');
  if (f._action == 'New') {
    f.setItemValues('ma_tt, ten_tt%l', [f._tths, f._tentths]);
    f.request('DefautFormValue', 'DefautFormValue', [['ma_hs', 'String', '']]);
  }
}
function setViewPanelImage(f, v) {
  var g = f.grid, img = '<img id="view_image" src="' + v + '">';;
  var id = f.get_id() + '_view_image';
  if ($get(id)) $get(id).innerHTML = img;
}
function showBlankImage(f) {
  var id = f._controller + '_view_image';
  if $get(id) $get(id).innerHTML = '<div class="ViewBlank"></div>';
}
function resetTicket(f, v, name) {
  f.setItemValue('ticket', v);
  if (name) f.focus(name);
}
function onFileSelected(e) {
  var o = $get('empImage').parentNode;
  var h = '<img id="empImage" style="width:60px;height:80px;" src="%src%">';
  if (window.FileReader) {
    var reader = new FileReader(), file = e.target.files[0];
    reader.onload = function(e) { o.innerHTML = h.replace('%src%', e.target.result); }
    if (file) reader.readAsDataURL(file);
  }
  else o.innerHTML = h.replace('%src%', '../Images/Attach.png');
}
function getFileName(s) {
  var p = s.lastIndexOf('\\');
  if (p != -1) {return s.substring(p + 1);}
  else {return s;}
}
function getRandomKey(l) {
	var s = '', c = '0123456789abcdefghiklmnopqrstuvwxyz';
	for (var i = 0; i < l; i++) {
		var r = Math.floor(Math.random() * c.length);
		s += c.substring(r, r + 1);
	}
  return s;
}
function loadApplicantImage(f) {
  var k = f.getItemValue('stt_rec'), src = f.getItemValue('imageurl');
  var o = $get('empImage'), b = (f._action == 'New') || (src == '');
  o.parentNode.parentNode.setAttribute('rowspan', 4);
  b ? o.parentNode.innerHTML = '<div id = "empImage" class="ViewBlank"/>' : o.src = src;
}
function onChange$Period(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('ma_vtr');
  f.setReferenceKeyFilter('ma_bp');
}
function onChange$Vacancy(o) {
  o.parentForm.setReferenceKeyFilter('ma_bp');
}
/* </flatten> */
      &ListScript;
      &PostScript;
      &ScriptIrregular;
      &CheckValidEmailFunction;
